import{_ as a,o as d,c as r,ag as l}from"./chunks/framework.Vng7Hdlh.js";const u=JSON.parse('{"title":"11. 在庫・レシピ管理","description":"","frontmatter":{},"headers":[],"relativePath":"internal/features/11-inventory.md","filePath":"internal/features/11-inventory.md"}'),e={name:"internal/features/11-inventory.md"};function i(o,t,h,n,s,c){return d(),r("div",null,[...t[0]||(t[0]=[l('<h1 id="_11-在庫・レシピ管理" tabindex="-1">11. 在庫・レシピ管理 <a class="header-anchor" href="#_11-在庫・レシピ管理" aria-label="Permalink to &quot;11. 在庫・レシピ管理&quot;">​</a></h1><p>在庫管理機能は<strong>proプラン以上</strong>で利用できます。管理ダッシュボードの「在庫・レシピ」タブから、食材の在庫管理、レシピ設定、棚卸しを行います。マネージャーのみ操作できます。</p><h2 id="_11-1-原材料一覧" tabindex="-1">11.1 原材料一覧 <a class="header-anchor" href="#_11-1-原材料一覧" aria-label="Permalink to &quot;11.1 原材料一覧&quot;">​</a></h2><p>「在庫・レシピ」タブ → 「原材料一覧」サブタブで、食材（原材料）の登録・管理を行います。</p><h3 id="原材料の登録" tabindex="-1">原材料の登録 <a class="header-anchor" href="#原材料の登録" aria-label="Permalink to &quot;原材料の登録&quot;">​</a></h3><ol><li>「原材料追加」ボタンをクリックします</li><li>モーダルが開きます</li><li>以下のフィールドに入力します</li></ol><table tabindex="0"><thead><tr><th>フィールド</th><th>種類</th><th>必須</th><th>説明</th></tr></thead><tbody><tr><td>原材料名</td><td>テキスト</td><td>✅</td><td>食材の名前（例：「鶏もも肉」「トマト」）</td></tr><tr><td>単位</td><td>セレクト</td><td>✅</td><td>g / ml / 個 / 枚 から選択</td></tr><tr><td>在庫数量</td><td>数値</td><td>—</td><td>現在の在庫量</td></tr><tr><td>単価</td><td>数値</td><td>—</td><td>1単位あたりの原価（円）</td></tr><tr><td>低在庫閾値</td><td>数値</td><td>—</td><td>この数量を下回ると低在庫警告が表示されます</td></tr></tbody></table><ol start="4"><li>「保存」ボタンをクリックします</li></ol><h3 id="原材料一覧の表示" tabindex="-1">原材料一覧の表示 <a class="header-anchor" href="#原材料一覧の表示" aria-label="Permalink to &quot;原材料一覧の表示&quot;">​</a></h3><p>各原材料には以下が表示されます。</p><table tabindex="0"><thead><tr><th>表示要素</th><th>説明</th></tr></thead><tbody><tr><td>原材料名</td><td>—</td></tr><tr><td>単位</td><td>g、ml、個、枚</td></tr><tr><td>在庫数量</td><td>現在の在庫量。低在庫時はハイライト表示</td></tr><tr><td>単価</td><td>1単位あたりの原価</td></tr><tr><td>低在庫閾値</td><td>—</td></tr><tr><td>レシピ使用数</td><td>この原材料を使用しているレシピの数</td></tr><tr><td>ステータス</td><td>有効/無効</td></tr></tbody></table><p><strong>在庫レベルの色分け：</strong></p><ul><li>通常：標準表示</li><li>低在庫（閾値以下）：黄色ハイライト</li><li>在庫切れ（0以下）：赤色ハイライト</li></ul><h3 id="原材料の編集・削除" tabindex="-1">原材料の編集・削除 <a class="header-anchor" href="#原材料の編集・削除" aria-label="Permalink to &quot;原材料の編集・削除&quot;">​</a></h3><ul><li><strong>編集：</strong> 全フィールドの変更、有効/無効の切替</li><li><strong>削除：</strong> 論理削除（データは保持されます）</li></ul><h3 id="csv入出力" tabindex="-1">CSV入出力 <a class="header-anchor" href="#csv入出力" aria-label="Permalink to &quot;CSV入出力&quot;">​</a></h3><ul><li><strong>エクスポート：</strong> 原材料一覧をCSVファイルとしてダウンロード</li><li><strong>インポート：</strong> CSVファイルから一括で原材料を登録・更新</li></ul><hr><h2 id="_11-2-レシピ設定" tabindex="-1">11.2 レシピ設定 <a class="header-anchor" href="#_11-2-レシピ設定" aria-label="Permalink to &quot;11.2 レシピ設定&quot;">​</a></h2><p>「在庫・レシピ」タブ → 「レシピ設定」サブタブで、メニューと原材料の紐づけ（レシピ）を管理します。</p><h3 id="レシピとは" tabindex="-1">レシピとは <a class="header-anchor" href="#レシピとは" aria-label="Permalink to &quot;レシピとは&quot;">​</a></h3><p>レシピは「メニュー1品あたりに使用する原材料と数量」の定義です。</p><p><strong>例：「チキンカレー」のレシピ</strong></p><ul><li>鶏もも肉：200g</li><li>玉ねぎ：100g</li><li>カレールー：50g</li><li>ごはん：250g</li></ul><h3 id="レシピの設定" tabindex="-1">レシピの設定 <a class="header-anchor" href="#レシピの設定" aria-label="Permalink to &quot;レシピの設定&quot;">​</a></h3><ol><li>メニュー品目を選択します</li><li>「レシピ編集」ボタンをクリックします</li><li>原材料を追加します</li></ol><table tabindex="0"><thead><tr><th>フィールド</th><th>説明</th></tr></thead><tbody><tr><td>原材料</td><td>登録済み原材料から選択（未使用・有効なもののみ表示）</td></tr><tr><td>使用量</td><td>1品あたりの使用量</td></tr><tr><td>単位</td><td>原材料の単位が自動表示</td></tr><tr><td>現在の在庫</td><td>原材料の現在の在庫量を参考表示</td></tr></tbody></table><ol start="4"><li>必要な原材料を全て追加したら「保存」ボタンをクリックします</li></ol><h3 id="レシピのcsv入出力" tabindex="-1">レシピのCSV入出力 <a class="header-anchor" href="#レシピのcsv入出力" aria-label="Permalink to &quot;レシピのCSV入出力&quot;">​</a></h3><ul><li><strong>エクスポート：</strong> レシピデータをCSVファイルとしてダウンロード</li><li><strong>インポート：</strong> CSVファイルから一括でレシピを登録・更新</li></ul><hr><h2 id="_11-3-棚卸し" tabindex="-1">11.3 棚卸し <a class="header-anchor" href="#_11-3-棚卸し" aria-label="Permalink to &quot;11.3 棚卸し&quot;">​</a></h2><p>棚卸し機能で、実際の在庫数量を確認・修正します。</p><h3 id="棚卸しの実行" tabindex="-1">棚卸しの実行 <a class="header-anchor" href="#棚卸しの実行" aria-label="Permalink to &quot;棚卸しの実行&quot;">​</a></h3><ol><li>「棚卸しモード」をONにします</li><li>各原材料の在庫数量が編集可能になります</li><li>実際の在庫を数えて数量を入力します</li><li>「一括保存」ボタンをクリックします</li><li>全ての変更がトランザクションで一括保存されます</li><li>更新された件数が表示されます</li></ol><div class="tip custom-block"><p class="custom-block-title">定期的な棚卸し</p><p>在庫の正確性を保つため、週1回または月1回の棚卸しを推奨します。棚卸し結果は在庫管理の基礎データとなり、AI需要予測の精度にも影響します。</p></div><hr><h2 id="_11-4-ai需要予測" tabindex="-1">11.4 AI需要予測 <a class="header-anchor" href="#_11-4-ai需要予測" aria-label="Permalink to &quot;11.4 AI需要予測&quot;">​</a></h2><p>proプラン以上で在庫管理が有効な場合、AIによる需要予測機能が利用できます。</p><h3 id="予測の仕組み" tabindex="-1">予測の仕組み <a class="header-anchor" href="#予測の仕組み" aria-label="Permalink to &quot;予測の仕組み&quot;">​</a></h3><ol><li>過去7日間の売上データを収集します</li><li>品目別の販売数量、曜日別パターンを分析します</li><li>レシピ情報と組み合わせて、必要な原材料量を予測します</li></ol><h3 id="aiからの出力" tabindex="-1">AIからの出力 <a class="header-anchor" href="#aiからの出力" aria-label="Permalink to &quot;AIからの出力&quot;">​</a></h3><table tabindex="0"><thead><tr><th>セクション</th><th>内容</th></tr></thead><tbody><tr><td>日別需要予測</td><td>今後の日ごとの品目別販売予測</td></tr><tr><td>原材料発注推奨</td><td>不足が見込まれる原材料と推奨発注量</td></tr><tr><td>低在庫アラート</td><td>閾値を下回る見込みの原材料</td></tr><tr><td>ポーション調整</td><td>使い切りのためのポーション調整提案</td></tr></tbody></table>',43)])])}const p=a(e,[["render",i]]);export{u as __pageData,p as default};
